/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;

    // Step 1: Preprocessing - Prefix Sum for even numbers
    // P[i] stores the count of even numbers in nums[0...i]
    const P = new Array(N).fill(0);
    for (let i = 0; i < N; i++) {
        const isEven = (nums[i] % 2 === 0) ? 1 : 0;
        P[i] = (i > 0 ? P[i - 1] : 0) + isEven;
    }

    /**
     * Finds the index j_max such that nums[j_max] <= V and j_max is maximized.
     * Returns -1 if all elements are > V.
     * Uses binary search (equivalent to upper_bound - 1).
     * @param {number} V The upper bound value.
     * @returns {number} The index j_max, or -1.
     */
    const upper_bound_index = (V) => {
        let low = 0;
        let high = N - 1;
        let result_index = -1;

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= V) {
                result_index = mid;
                low = mid + 1; // Try to find a larger index
            } else {
                high = mid - 1; // Too large
            }
        }
        return result_index;
    };

    /**
     * Checks if the count of remaining even numbers <= 2M is at least k.
     * @param {number} M Represents M = X/2, where X=2M is the candidate answer.
     * @param {number} l Start index of the subarray.
     * @param {number} r End index of the subarray.
     * @param {number} k The target rank.
     * @returns {boolean} True if the k-th smallest remaining element is <= 2M.
     */
    const check = (M, l, r, k) => {
        const V = 2 * M;

        // Step 1: Find j_max: index of the largest element <= V
        const j_max = upper_bound_index(V);

        // The effective upper bound for counting removed elements in the range [l, r]
        // must respect both r and j_max.
        let r_prime = Math.min(r, j_max);

        // If r_prime < l, no element in nums[l..r] is <= V, so 0 elements are removed.
        if (r_prime < l) {
            const removedCount = 0;
            const remainingCount = M - removedCount;
            return remainingCount >= k;
        }

        // Step 2: Count removed elements (even numbers in nums[l..r_prime])
        // Count = P[r_prime] - P[l-1]
        const count_before_l = (l > 0) ? P[l - 1] : 0;
        const removedCount = P[r_prime] - count_before_l;

        // Total evens <= V in E is M (since X=2M)
        const remainingCount = M - removedCount;

        return remainingCount >= k;
    };

    const results = [];

    // Process each query
    for (const query of queries) {
        const [l, r, k] = query;

        // Binary Search for the smallest M such that check(M) is true.
        // M represents X/2. 

        // Lower bound L: Smallest possible M is 1 (X=2)
        let L = 1;
        // Upper bound R: If nothing is removed, answer is 2k, so M=k. We use a safe margin.
        let R = 2 * k + 2; 

        let ans_M = R; // Stores the smallest M found so far

        while (L <= R) {
            // Use Math.floor for integer division
            const M_mid = Math.floor((L + R) / 2);

            if (check(M_mid, l, r, k)) {
                ans_M = M_mid;
                R = M_mid - 1; // Try for an even smaller M
            } else {
                L = M_mid + 1; // M is too small, need a larger M
            }
        }

        // The result is X = 2 * ans_M
        results.push(2 * ans_M);
    }

    return results;
}

